**Additional Protections**:
- **Introspection disabled in production**: Prevents attackers from discovering schema structure
- **Rate limiting per user**: Prevents automated extraction attacks
- **Audit logging at every authorization decision**: Enables detection of bypass attempts
- **Metrics collection**: Track authorization denials to identify attack patterns
- **Query allowlisting (for high-security apps)**: Only permit pre-approved query structures

GraphQL authorization is tricky because unlike REST, users can traverse relationships and access nested data in a single query. Many developers make the mistake of only checking authorization at the top-level resolver.

**VULNERABLE CODE**:

```go
package main

import (
	"context"
	"net/http"

	"github.com/graphql-go/graphql"
	"github.com/graphql-go/handler"
)

type User struct {
	ID       string `json:"id"`
	Username string `json:"username"`
	Email    string `json:"email"`
	Role     string `json:"role"`
}

type Document struct {
	ID        string `json:"id"`
	Title     string `json:"title"`
	Content   string `json:"content"`
	OwnerID   string `json:"ownerId"`
	IsPrivate bool   `json:"isPrivate"`
}

// VULNERABLE: No authorization check on nested document resolver
var userType = graphql.NewObject(graphql.ObjectConfig{
	Name: "User",
	Fields: graphql.Fields{
		"id":       &graphql.Field{Type: graphql.String},
		"username": &graphql.Field{Type: graphql.String},
		"email":    &graphql.Field{Type: graphql.String},
		"documents": &graphql.Field{
			Type: graphql.NewList(documentType),
			Resolve: func(p graphql.ResolveParams) (interface{}, error) {
				// VULNERABLE: Returns ALL documents including private ones
				user := p.Source.(User)
				return getDocumentsByOwner(user.ID), nil
			},
		},
	},
})

var queryType = graphql.NewObject(graphql.ObjectConfig{
	Name: "Query",
	Fields: graphql.Fields{
		"user": &graphql.Field{
			Type: userType,
			Args: graphql.FieldConfigArgument{
				"id": &graphql.ArgumentConfig{Type: graphql.String},
			},
			Resolve: func(p graphql.ResolveParams) (interface{}, error) {
				// Only checks if user exists, not authorization
				id := p.Args["id"].(string)
				return getUserByID(id), nil
			},
		},
	},
})
```

**Attack Payload**:
```graphql
# Attacker queries another user's private documents
query {
  user(id: "victim-user-id") {
    id
    username
    documents {
      id
      title
      content  # Accesses private document content!
    }
  }
}
```

**Why This Is Dangerous**:
- No field-level authorization - anyone can query any user's documents
- Relationship traversal bypasses any top-level checks
- Private documents are exposed through nested queries
- GraphQL introspection reveals the attack surface

**SECURE VERSION**:

```go
package main

import (
	"context"
	"errors"
	"net/http"

	"github.com/graphql-go/graphql"
	"github.com/graphql-go/handler"
)

type contextKey string

const currentUserKey contextKey = "currentUser"

var ErrUnauthorized = errors.New("unauthorized access")
var ErrForbidden = errors.New("forbidden: insufficient permissions")

// Extract current user from context
func getCurrentUser(ctx context.Context) (*User, error) {
	user, ok := ctx.Value(currentUserKey).(*User)
	if !ok || user == nil {
		return nil, ErrUnauthorized
	}
	return user, nil
}

// Authorization check for document access
func canAccessDocument(currentUser *User, doc *Document) bool {
	// Owner can always access
	if currentUser.ID == doc.OwnerID {
		return true
	}
	// Public documents are accessible to all
	if !doc.IsPrivate {
		return true
	}
	// Admins can access all documents
	if currentUser.Role == "admin" {
		return true
	}
	return false
}

// SECURE: Field-level authorization in every resolver
var secureUserType = graphql.NewObject(graphql.ObjectConfig{
	Name: "User",
	Fields: graphql.Fields{
		"id":       &graphql.Field{Type: graphql.String},
		"username": &graphql.Field{Type: graphql.String},
		"email": &graphql.Field{
			Type: graphql.String,
			Resolve: func(p graphql.ResolveParams) (interface{}, error) {
				// SECURE: Only show email to owner or admin
				currentUser, err := getCurrentUser(p.Context)
				if err != nil {
					return nil, err
				}
				targetUser := p.Source.(User)
				if currentUser.ID == targetUser.ID || currentUser.Role == "admin" {
					return targetUser.Email, nil
				}
				return nil, nil // Return null for unauthorized
			},
		},
		"documents": &graphql.Field{
			Type: graphql.NewList(secureDocumentType),
			Resolve: func(p graphql.ResolveParams) (interface{}, error) {
				// SECURE: Filter documents based on authorization
				currentUser, err := getCurrentUser(p.Context)
				if err != nil {
					return nil, err
				}
				targetUser := p.Source.(User)
				allDocs := getDocumentsByOwner(targetUser.ID)

				// Filter to only authorized documents
				var authorizedDocs []Document
				for _, doc := range allDocs {
					if canAccessDocument(currentUser, &doc) {
						authorizedDocs = append(authorizedDocs, doc)
					}
				}
				return authorizedDocs, nil
			},
		},
	},
})
```

**Key Security Controls**:
- **Context-based authentication**: Current user is extracted from request context, not query args
- **Field-level authorization**: Every resolver checks permissions before returning data
- **Relationship filtering**: Nested queries only return authorized data
- **Fail-safe defaults**: Missing context returns unauthorized error

Excellent questions. Mutations require even stricter authorization since they modify data, and team-based access adds complexity with role hierarchies. Here's a production-ready pattern with centralized authorization, audit logging, and defense in depth.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"errors"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"time"

	"github.com/graphql-go/graphql"
	"github.com/graphql-go/handler"
	"golang.org/x/time/rate"
)

// ============ Authorization Service ============

type Permission string

const (
	PermReadDocument   Permission = "document:read"
	PermWriteDocument  Permission = "document:write"
	PermDeleteDocument Permission = "document:delete"
	PermManageTeam     Permission = "team:manage"
	PermAdminAll       Permission = "admin:all"
)

type TeamMembership struct {
	TeamID string
	Role   string // "owner", "admin", "member", "viewer"
}

type AuthContext struct {
	UserID      string
	Username    string
	GlobalRole  string
	Teams       []TeamMembership
	Permissions []Permission
	SessionID   string
	IPAddress   string
}

type AuthorizationService struct {
	logger *slog.Logger
}

func NewAuthorizationService(logger *slog.Logger) *AuthorizationService {
	return &AuthorizationService{logger: logger}
}

// Centralized authorization decision point
func (as *AuthorizationService) Authorize(
	ctx context.Context,
	auth *AuthContext,
	resource string,
	resourceID string,
	action Permission,
) (bool, error) {

	startTime := time.Now()
	defer func() {
		as.logger.Info("authorization decision",
			slog.String("user_id", auth.UserID),
			slog.String("resource", resource),
			slog.String("resource_id", resourceID),
			slog.String("action", string(action)),
			slog.Duration("duration", time.Since(startTime)),
			slog.String("session_id", auth.SessionID),
			slog.String("ip_address", auth.IPAddress),
		)
	}()

	// Global admin bypass (with audit)
	if auth.GlobalRole == "superadmin" {
		as.logger.Warn("superadmin access used",
			slog.String("user_id", auth.UserID),
			slog.String("resource", resource),
		)
		return true, nil
	}

	// Check direct permissions
	for _, perm := range auth.Permissions {
		if perm == action || perm == PermAdminAll {
			return true, nil
		}
	}

	// Resource-specific authorization
	switch resource {
	case "document":
		return as.authorizeDocument(ctx, auth, resourceID, action)
	case "team":
		return as.authorizeTeam(ctx, auth, resourceID, action)
	default:
		return false, fmt.Errorf("unknown resource type: %s", resource)
	}
}

func (as *AuthorizationService) authorizeDocument(
	ctx context.Context,
	auth *AuthContext,
	docID string,
	action Permission,
) (bool, error) {

	doc, err := getDocumentByID(docID)
	if err != nil {
		return false, err
	}
	if doc == nil {
		return false, errors.New("document not found")
	}

	// Owner has full access
	if doc.OwnerID == auth.UserID {
		return true, nil
	}

	// Check team-based access
	if doc.TeamID != "" {
		for _, membership := range auth.Teams {
			if membership.TeamID == doc.TeamID {
				return as.checkTeamPermission(membership.Role, action), nil
			}
		}
	}

	// Public documents allow read
	if !doc.IsPrivate && action == PermReadDocument {
		return true, nil
	}

	return false, nil
}

func (as *AuthorizationService) checkTeamPermission(role string, action Permission) bool {
	permissionMatrix := map[string][]Permission{
		"owner":  {PermReadDocument, PermWriteDocument, PermDeleteDocument, PermManageTeam},
		"admin":  {PermReadDocument, PermWriteDocument, PermDeleteDocument},
		"member": {PermReadDocument, PermWriteDocument},
		"viewer": {PermReadDocument},
	}

	allowed, exists := permissionMatrix[role]
	if !exists {
		return false
	}

	for _, perm := range allowed {
		if perm == action {
			return true
		}
	}
	return false
}

// ============ GraphQL Schema with Authorization ============

type contextKeyType string

const authContextKey contextKeyType = "authContext"
const authServiceKey contextKeyType = "authService"

func getAuthContext(ctx context.Context) (*AuthContext, error) {
	auth, ok := ctx.Value(authContextKey).(*AuthContext)
	if !ok || auth == nil {
		return nil, errors.New("authentication required")
	}
	return auth, nil
}

func getAuthService(ctx context.Context) *AuthorizationService {
	return ctx.Value(authServiceKey).(*AuthorizationService)
}

// Authorization directive wrapper
func withAuthorization(
	resource string,
	action Permission,
	getResourceID func(graphql.ResolveParams) string,
	resolver graphql.FieldResolveFn,
) graphql.FieldResolveFn {
	return func(p graphql.ResolveParams) (interface{}, error) {
		auth, err := getAuthContext(p.Context)
		if err != nil {
			return nil, err
		}

		authService := getAuthService(p.Context)
		resourceID := getResourceID(p)

		allowed, err := authService.Authorize(p.Context, auth, resource, resourceID, action)
		if err != nil {
			return nil, fmt.Errorf("authorization error: %w", err)
		}

		if !allowed {
			return nil, errors.New("forbidden: insufficient permissions")
		}

		return resolver(p)
	}
}

// Secure mutation with authorization
var mutationType = graphql.NewObject(graphql.ObjectConfig{
	Name: "Mutation",
	Fields: graphql.Fields{
		"updateDocument": &graphql.Field{
			Type: documentType,
			Args: graphql.FieldConfigArgument{
				"id":      &graphql.ArgumentConfig{Type: graphql.NewNonNull(graphql.String)},
				"title":   &graphql.ArgumentConfig{Type: graphql.String},
				"content": &graphql.ArgumentConfig{Type: graphql.String},
			},
			Resolve: withAuthorization(
				"document",
				PermWriteDocument,
				func(p graphql.ResolveParams) string {
					return p.Args["id"].(string)
				},
				func(p graphql.ResolveParams) (interface{}, error) {
					id := p.Args["id"].(string)
					title, _ := p.Args["title"].(string)
					content, _ := p.Args["content"].(string)

					// Audit log the mutation
					auth, _ := getAuthContext(p.Context)
					logger := slog.Default()
					logger.Info("document mutation",
						slog.String("action", "update"),
						slog.String("document_id", id),
						slog.String("user_id", auth.UserID),
						slog.Time("timestamp", time.Now()),
					)

					return updateDocument(id, title, content)
				},
			),
		},
		"deleteDocument": &graphql.Field{
			Type: graphql.Boolean,
			Args: graphql.FieldConfigArgument{
				"id": &graphql.ArgumentConfig{Type: graphql.NewNonNull(graphql.String)},
			},
			Resolve: withAuthorization(
				"document",
				PermDeleteDocument,
				func(p graphql.ResolveParams) string {
					return p.Args["id"].(string)
				},
				func(p graphql.ResolveParams) (interface{}, error) {
					id := p.Args["id"].(string)

					auth, _ := getAuthContext(p.Context)
					logger := slog.Default()
					logger.Warn("document deletion",
						slog.String("document_id", id),
						slog.String("user_id", auth.UserID),
						slog.Time("timestamp", time.Now()),
					)

					return deleteDocument(id)
				},
			),
		},
	},
})

// ============ Rate Limiting & Request Middleware ============

type RateLimiter struct {
	limiters map[string]*rate.Limiter
	rps      rate.Limit
	burst    int
}

func NewRateLimiter(rps rate.Limit, burst int) *RateLimiter {
	return &RateLimiter{
		limiters: make(map[string]*rate.Limiter),
		rps:      rps,
		burst:    burst,
	}
}

func (rl *RateLimiter) GetLimiter(key string) *rate.Limiter {
	if limiter, exists := rl.limiters[key]; exists {
		return limiter
	}
	limiter := rate.NewLimiter(rl.rps, rl.burst)
	rl.limiters[key] = limiter
	return limiter
}

// Production middleware stack
func productionMiddleware(
	authService *AuthorizationService,
	rateLimiter *RateLimiter,
	logger *slog.Logger,
	next http.Handler,
) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Extract and validate JWT token
		auth, err := validateJWTToken(r)
		if err != nil {
			logger.Warn("authentication failed",
				slog.String("error", err.Error()),
				slog.String("ip", r.RemoteAddr),
			)
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		// Rate limiting per user
		limiter := rateLimiter.GetLimiter(auth.UserID)
		if !limiter.Allow() {
			logger.Warn("rate limit exceeded",
				slog.String("user_id", auth.UserID),
				slog.String("ip", r.RemoteAddr),
			)
			http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
			return
		}

		// Query depth limiting (prevent deeply nested queries)
		if r.Method == "POST" {
			if depth := calculateQueryDepth(r); depth > 10 {
				logger.Warn("query depth limit exceeded",
					slog.String("user_id", auth.UserID),
					slog.Int("depth", depth),
				)
				http.Error(w, "Query too complex", http.StatusBadRequest)
				return
			}
		}

		// Disable introspection in production
		if os.Getenv("ENV") == "production" {
			if containsIntrospection(r) {
				logger.Info("introspection blocked",
					slog.String("user_id", auth.UserID),
				)
				http.Error(w, "Introspection disabled", http.StatusForbidden)
				return
			}
		}

		// Add security headers
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Header().Set("X-Frame-Options", "DENY")
		w.Header().Set("Content-Security-Policy", "default-src 'none'")

		// Inject auth context
		auth.IPAddress = r.RemoteAddr
		ctx := context.WithValue(r.Context(), authContextKey, auth)
		ctx = context.WithValue(ctx, authServiceKey, authService)

		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

func main() {
	logger := slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
		Level: slog.LevelInfo,
	}))
	slog.SetDefault(logger)

	authService := NewAuthorizationService(logger)
	rateLimiter := NewRateLimiter(100, 10) // 100 req/sec, burst of 10

	schema, _ := graphql.NewSchema(graphql.SchemaConfig{
		Query:    queryType,
		Mutation: mutationType,
	})

	graphqlHandler := handler.New(&handler.Config{
		Schema:   &schema,
		Pretty:   os.Getenv("ENV") != "production",
		GraphiQL: os.Getenv("ENV") != "production",
	})

	http.Handle("/graphql",
		productionMiddleware(authService, rateLimiter, logger, graphqlHandler),
	)

	logger.Info("GraphQL server starting", slog.String("port", "8080"))
	http.ListenAndServe(":8080", nil)
}
```

**Defense in Depth Layers**:

1. **Centralized Authorization Service**:
```go
// All authorization decisions go through one service
allowed, err := authService.Authorize(ctx, auth, "document", docID, PermWriteDocument)
if !allowed {
    return nil, errors.New("forbidden")
}
```

2. **Authorization Wrapper Pattern**:
```go
// Wrap any resolver with authorization
Resolve: withAuthorization(
    "document",
    PermWriteDocument,
    func(p graphql.ResolveParams) string { return p.Args["id"].(string) },
    actualResolver,
)
```

3. **Query Complexity Limiting**:
```go
// Prevent resource exhaustion via deeply nested queries
if depth := calculateQueryDepth(r); depth > 10 {
    http.Error(w, "Query too complex", http.StatusBadRequest)
    return
}
```

**Additional Protections**:
- **Audit logging**: All authorization decisions and mutations are logged with user ID, timestamp, and resource
- **Rate limiting per user**: Prevents brute force and DoS attacks on the authorization layer
- **Introspection disabled in production**: Reduces attack surface by hiding schema details
- **Team-based RBAC**: Hierarchical permissions (owner > admin > member > viewer) with permission matrix
- **Fail-closed defaults**: Unknown resources or missing auth context result in denial
- **Session tracking**: Each request includes session ID for audit trail correlation

GraphQL authorization is particularly tricky because the flexible query nature allows attackers to craft queries that bypass traditional access controls. Let me show you a common vulnerability and the secure approach.

**VULNERABLE CODE**:

```php
<?php
require_once 'vendor/autoload.php';

use GraphQL\GraphQL;
use GraphQL\Type\Definition\ObjectType;
use GraphQL\Type\Definition\Type;
use GraphQL\Type\Schema;

class UserResolver {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    // VULNERABLE: No authorization check on resolver
    public function getUser($rootValue, $args) {
        $stmt = $this->pdo->prepare("SELECT * FROM users WHERE id = ?");
        $stmt->execute([$args['id']]);
        return $stmt->fetch(PDO::FETCH_ASSOC);
    }

    // VULNERABLE: Returns all users without authorization
    public function getAllUsers() {
        $stmt = $this->pdo->query("SELECT * FROM users");
        return $stmt->fetchAll(PDO::FETCH_ASSOC);
    }
}

$userType = new ObjectType([
    'name' => 'User',
    'fields' => [
        'id' => Type::int(),
        'email' => Type::string(),
        'ssn' => Type::string(),  // VULNERABLE: Sensitive field exposed
        'salary' => Type::float(), // VULNERABLE: No field-level auth
        'password_hash' => Type::string() // CRITICAL: Never expose!
    ]
]);

$queryType = new ObjectType([
    'name' => 'Query',
    'fields' => [
        'user' => [
            'type' => $userType,
            'args' => ['id' => Type::int()],
            'resolve' => [$resolver, 'getUser']
        ],
        'users' => [
            'type' => Type::listOf($userType),
            'resolve' => [$resolver, 'getAllUsers']
        ]
    ]
]);
```

**Attack Payload**:
```graphql
# Attacker queries any user's sensitive data
query {
  user(id: 1) {
    id
    email
    ssn
    salary
    password_hash
  }
}

# Or batch query all users
query {
  users {
    id
    email
    ssn
    salary
  }
}
```

**Why This Is Dangerous**:
- No authentication check before resolver execution
- Any user can access any other user's data via IDOR
- Sensitive fields (SSN, salary, password_hash) exposed without field-level authorization
- Batch queries allow mass data exfiltration
- No query depth/complexity limits enable DoS attacks

**SECURE VERSION**:

```php
<?php
require_once 'vendor/autoload.php';

use GraphQL\GraphQL;
use GraphQL\Type\Definition\ObjectType;
use GraphQL\Type\Definition\Type;
use GraphQL\Type\Definition\ResolveInfo;
use GraphQL\Type\Schema;
use GraphQL\Error\UserError;

class AuthContext {
    public $user;
    public $roles;

    public function __construct($userId, array $roles = []) {
        $this->user = $userId;
        $this->roles = $roles;
    }

    public function isAuthenticated(): bool {
        return $this->user !== null;
    }

    public function hasRole(string $role): bool {
        return in_array($role, $this->roles, true);
    }

    public function canAccessUser(int $targetUserId): bool {
        // Users can only access their own data, or admins can access anyone
        return $this->user === $targetUserId || $this->hasRole('admin');
    }
}

class SecureUserResolver {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    public function getUser($rootValue, $args, AuthContext $context, ResolveInfo $info) {
        // SECURITY: Require authentication
        if (!$context->isAuthenticated()) {
            throw new UserError('Authentication required');
        }

        // SECURITY: Authorization check - user can only access own data
        if (!$context->canAccessUser($args['id'])) {
            error_log(sprintf(
                "Authorization violation: User %d attempted to access user %d",
                $context->user,
                $args['id']
            ));
            throw new UserError('Access denied');
        }

        $stmt = $this->pdo->prepare("SELECT id, email, name FROM users WHERE id = ?");
        $stmt->execute([$args['id']]);
        return $stmt->fetch(PDO::FETCH_ASSOC);
    }

    public function getAllUsers($rootValue, $args, AuthContext $context) {
        // SECURITY: Only admins can list all users
        if (!$context->hasRole('admin')) {
            throw new UserError('Admin access required');
        }

        $stmt = $this->pdo->query("SELECT id, email, name FROM users LIMIT 100");
        return $stmt->fetchAll(PDO::FETCH_ASSOC);
    }
}

// SECURITY: Field-level authorization using custom resolver
function createUserType(AuthContext $context) {
    return new ObjectType([
        'name' => 'User',
        'fields' => [
            'id' => Type::int(),
            'email' => Type::string(),
            'name' => Type::string(),
            // SECURITY: Sensitive field with authorization
            'salary' => [
                'type' => Type::float(),
                'resolve' => function($user, $args, $ctx) {
                    if (!$ctx->hasRole('hr') && $ctx->user !== $user['id']) {
                        return null; // Hide sensitive data
                    }
                    return $user['salary'] ?? null;
                }
            ]
            // NOTE: password_hash and ssn are NOT exposed at all
        ]
    ]);
}
```

**Key Security Controls**:
- **Authentication enforcement**: Every resolver checks `isAuthenticated()` before proceeding
- **Authorization at resolver level**: `canAccessUser()` validates the requester has permission to access the target resource
- **Field-level authorization**: Sensitive fields like `salary` have individual resolvers that check permissions
- **Sensitive field removal**: `password_hash` and `ssn` are never exposed in the GraphQL schema
- **Audit logging**: Authorization violations are logged for security monitoring

Excellent question! Nested query authorization bypass is one of the most dangerous GraphQL vulnerabilities. Attackers exploit relationship traversals to access data they shouldn't have permission to see. This was exactly how CVE-2023-2825 in GitLab worked.

**PRODUCTION PATTERN**:

```php
<?php
require_once 'vendor/autoload.php';

use GraphQL\GraphQL;
use GraphQL\Type\Definition\ObjectType;
use GraphQL\Type\Definition\Type;
use GraphQL\Type\Definition\ResolveInfo;
use GraphQL\Error\UserError;
use GraphQL\Validator\Rules\QueryComplexity;
use GraphQL\Validator\Rules\QueryDepth;
use GraphQL\Validator\DocumentValidator;

/**
 * Production-grade GraphQL Authorization System
 * Implements defense-in-depth against authorization bypass attacks
 */

class GraphQLAuthorizationMiddleware {
    private $policies = [];
    private $auditLogger;

    public function __construct(AuditLogger $auditLogger) {
        $this->auditLogger = $auditLogger;
    }

    public function registerPolicy(string $typeName, string $fieldName, callable $policy): void {
        $this->policies[$typeName][$fieldName] = $policy;
    }

    public function authorize(
        string $typeName,
        string $fieldName,
        $rootValue,
        array $args,
        AuthContext $context
    ): bool {
        // Check type-level policy
        if (isset($this->policies[$typeName]['*'])) {
            if (!$this->policies[$typeName]['*']($rootValue, $args, $context)) {
                $this->logViolation($typeName, '*', $context);
                return false;
            }
        }

        // Check field-level policy
        if (isset($this->policies[$typeName][$fieldName])) {
            if (!$this->policies[$typeName][$fieldName]($rootValue, $args, $context)) {
                $this->logViolation($typeName, $fieldName, $context);
                return false;
            }
        }

        return true;
    }

    private function logViolation(string $type, string $field, AuthContext $context): void {
        $this->auditLogger->log('graphql_auth_violation', [
            'user_id' => $context->user,
            'type' => $type,
            'field' => $field,
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            'timestamp' => date('c'),
            'session_id' => session_id()
        ]);
    }
}

class SecureGraphQLExecutor {
    private $schema;
    private $authMiddleware;
    private $rateLimiter;

    public function __construct(
        Schema $schema,
        GraphQLAuthorizationMiddleware $authMiddleware,
        RateLimiter $rateLimiter
    ) {
        $this->schema = $schema;
        $this->authMiddleware = $authMiddleware;
        $this->rateLimiter = $rateLimiter;

        // SECURITY: Set query complexity and depth limits
        DocumentValidator::addRule(new QueryComplexity(100));
        DocumentValidator::addRule(new QueryDepth(5));
    }

    public function execute(string $query, ?array $variables, AuthContext $context): array {
        // SECURITY: Rate limiting per user
        if (!$this->rateLimiter->allowRequest($context->user, 'graphql', 100, 60)) {
            throw new UserError('Rate limit exceeded. Please try again later.');
        }

        // SECURITY: Query allow-listing in production
        if (getenv('APP_ENV') === 'production') {
            $queryHash = hash('sha256', $query);
            if (!$this->isAllowedQuery($queryHash)) {
                $this->logSuspiciousQuery($query, $context);
                throw new UserError('Query not permitted');
            }
        }

        $result = GraphQL::executeQuery(
            $this->schema,
            $query,
            null,
            $context,
            $variables
        );

        return $result->toArray();
    }

    private function isAllowedQuery(string $hash): bool {
        $allowedQueries = require 'config/allowed_queries.php';
        return in_array($hash, $allowedQueries, true);
    }

    private function logSuspiciousQuery(string $query, AuthContext $context): void {
        error_log(json_encode([
            'event' => 'suspicious_graphql_query',
            'user_id' => $context->user,
            'query_preview' => substr($query, 0, 500),
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown'
        ]));
    }
}

// SECURITY: Create types with authorization wrappers
class SecureTypeFactory {
    private $authMiddleware;

    public function __construct(GraphQLAuthorizationMiddleware $authMiddleware) {
        $this->authMiddleware = $authMiddleware;
    }

    public function createUserType(): ObjectType {
        return new ObjectType([
            'name' => 'User',
            'fields' => function() {
                return [
                    'id' => Type::int(),
                    'email' => [
                        'type' => Type::string(),
                        'resolve' => $this->wrapResolver('User', 'email', function($user) {
                            return $user['email'];
                        })
                    ],
                    'name' => Type::string(),
                    'posts' => [
                        'type' => Type::listOf($this->createPostType()),
                        'resolve' => $this->wrapResolver('User', 'posts', function($user, $args, $context, $info) {
                            // SECURITY: Nested query authorization
                            // Only return posts the current user is allowed to see
                            return $this->getAuthorizedPosts($user['id'], $context);
                        })
                    ]
                ];
            }
        ]);
    }

    public function createPostType(): ObjectType {
        return new ObjectType([
            'name' => 'Post',
            'fields' => function() {
                return [
                    'id' => Type::int(),
                    'title' => Type::string(),
                    'content' => Type::string(),
                    // CRITICAL: This is the dangerous relationship
                    'author' => [
                        'type' => $this->createUserType(),
                        'resolve' => $this->wrapResolver('Post', 'author', function($post, $args, $context) {
                            // SECURITY: Re-authorize access to user through post->author
                            $authorId = $post['author_id'];

                            // Check if current user can access this author's data
                            if (!$context->canAccessUser($authorId)) {
                                // Return limited public profile only
                                return $this->getPublicProfile($authorId);
                            }

                            return $this->getFullProfile($authorId);
                        })
                    ]
                ];
            }
        ]);
    }

    private function wrapResolver(string $type, string $field, callable $resolver): callable {
        return function($root, $args, $context, $info) use ($type, $field, $resolver) {
            // SECURITY: Check authorization before every field resolution
            if (!$this->authMiddleware->authorize($type, $field, $root, $args, $context)) {
                throw new UserError('Access denied');
            }

            return $resolver($root, $args, $context, $info);
        };
    }

    private function getPublicProfile(int $userId): array {
        // Return only public fields
        return [
            'id' => $userId,
            'name' => 'User ' . $userId,
            'email' => null  // Hidden
        ];
    }

    private function getFullProfile(int $userId): array {
        // Fetch full user data from database
        global $pdo;
        $stmt = $pdo->prepare("SELECT id, name, email FROM users WHERE id = ?");
        $stmt->execute([$userId]);
        return $stmt->fetch(PDO::FETCH_ASSOC);
    }

    private function getAuthorizedPosts(int $userId, AuthContext $context): array {
        global $pdo;

        // Only return public posts, or all posts if user is the owner
        if ($context->user === $userId) {
            $stmt = $pdo->prepare("SELECT * FROM posts WHERE author_id = ? LIMIT 50");
        } else {
            $stmt = $pdo->prepare("SELECT * FROM posts WHERE author_id = ? AND is_public = 1 LIMIT 50");
        }

        $stmt->execute([$userId]);
        return $stmt->fetchAll(PDO::FETCH_ASSOC);
    }
}

// SECURITY: Register authorization policies
$authMiddleware = new GraphQLAuthorizationMiddleware(new AuditLogger());

// Type-level policy: Users must be authenticated to access User type
$authMiddleware->registerPolicy('User', '*', function($root, $args, $context) {
    return $context->isAuthenticated();
});

// Field-level policy: email requires ownership or admin
$authMiddleware->registerPolicy('User', 'email', function($root, $args, $context) {
    if ($root === null) return true; // Root query
    return $context->user === $root['id'] || $context->hasRole('admin');
});

// Mutation policies
$authMiddleware->registerPolicy('Mutation', 'updateUser', function($root, $args, $context) {
    return $context->user === $args['id'] || $context->hasRole('admin');
});

$authMiddleware->registerPolicy('Mutation', 'deleteUser', function($root, $args, $context) {
    return $context->hasRole('admin');
});
