**Defense in Depth Layers**:

1. **Query Complexity & Depth Limits**:
```php
// Prevent resource exhaustion attacks
DocumentValidator::addRule(new QueryComplexity(100)); // Max complexity score
DocumentValidator::addRule(new QueryDepth(5)); // Max nesting depth
```

2. **Field-Level Authorization on Every Resolver**:
```php
// Every field resolution checks authorization
private function wrapResolver(string $type, string $field, callable $resolver): callable {
    return function($root, $args, $context, $info) use ($type, $field, $resolver) {
        if (!$this->authMiddleware->authorize($type, $field, $root, $args, $context)) {
            throw new UserError('Access denied');
        }
        return $resolver($root, $args, $context, $info);
    };
}
```

3. **Relationship Traversal Protection**:
```php
// When resolving post->author, re-check authorization
'author' => [
    'resolve' => function($post, $args, $context) {
        if (!$context->canAccessUser($post['author_id'])) {
            return $this->getPublicProfile($post['author_id']); // Limited data
        }
        return $this->getFullProfile($post['author_id']);
    }
]
```

**Additional Protections**:

- **Query Allow-listing**: In production, only pre-approved query hashes are permitted, preventing arbitrary query construction
- **Rate Limiting**: Per-user limits prevent enumeration and brute-force attacks
- **Audit Logging**: All authorization violations are logged with user ID, IP, timestamp for forensic analysis
- **Introspection Disabled in Production**: Disable `__schema` and `__type` queries to prevent schema discovery
- **Input Validation**: All arguments validated before processing with type coercion disabled
- **Error Masking**: Production errors return generic messages to prevent information disclosure

**Introspection Disabling**:
```php
// Disable introspection in production
if (getenv('APP_ENV') === 'production') {
    DocumentValidator::addRule(new DisableIntrospection());
}
```

GraphQL authorization is tricky because the nested query structure can bypass simple endpoint-level checks. Let me show you a common vulnerability and the secure approach.

**VULNERABLE CODE**:

```csharp
using HotChocolate;
using HotChocolate.Types;
using Microsoft.AspNetCore.Authorization;
using System.Collections.Generic;
using System.Linq;

namespace VulnerableGraphQL
{
    public class Query
    {
        // VULNERABLE: Only checks if user is authenticated, not ownership
        [Authorize]
        public User GetCurrentUser([Service] IUserRepository repo, [GlobalState] int currentUserId)
        {
            return repo.GetUserById(currentUserId);
        }

        // VULNERABLE: No authorization check at all on nested data
        public IQueryable<Order> GetOrders([Service] IOrderRepository repo)
        {
            return repo.GetAllOrders(); // Returns ALL orders!
        }
    }

    public class UserType : ObjectType<User>
    {
        protected override void Configure(IObjectTypeDescriptor<User> descriptor)
        {
            descriptor.Field(u => u.Id);
            descriptor.Field(u => u.Email);
            // VULNERABLE: Exposes orders without ownership check
            descriptor.Field(u => u.Orders);
            // VULNERABLE: Allows traversal to other users through relationships
            descriptor.Field(u => u.Friends);
        }
    }

    public class User
    {
        public int Id { get; set; }
        public string Email { get; set; }
        public string SocialSecurityNumber { get; set; } // Sensitive!
        public List<Order> Orders { get; set; }
        public List<User> Friends { get; set; } // Allows user traversal
    }

    public class Order
    {
        public int Id { get; set; }
        public int UserId { get; set; }
        public decimal Total { get; set; }
        public User Owner { get; set; } // Back-reference enables bypass
    }
}
```

**Attack Payload**:
```graphql
# Attacker bypasses authorization via nested query traversal
query {
  currentUser {
    friends {
      email
      socialSecurityNumber
      orders {
        total
        owner {
          friends {
            # Continue traversing to access ANY user's data
            email
            orders { total }
          }
        }
      }
    }
  }
}
```

**Why This Is Dangerous**:
- Field resolvers execute without authorization context validation
- Nested relationships allow traversal to unauthorized data
- The `[Authorize]` attribute only checks authentication, not data ownership
- Sensitive fields like SSN are exposed through object type definitions
- Attackers can enumerate the entire user graph through friend relationships

**SECURE VERSION**:

```csharp
using HotChocolate;
using HotChocolate.AspNetCore.Authorization;
using HotChocolate.Resolvers;
using HotChocolate.Types;
using Microsoft.AspNetCore.Authorization;
using System.Collections.Generic;
using System.Linq;
using System.Security.Claims;

namespace SecureGraphQL
{
    // Custom authorization handler for ownership checks
    public class OwnerAuthorizationHandler : AuthorizationHandler<OwnerRequirement, User>
    {
        protected override Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            OwnerRequirement requirement,
            User resource)
        {
            var userId = context.User.FindFirst(ClaimTypes.NameIdentifier)?.Value;

            if (int.TryParse(userId, out var id) && resource.Id == id)
            {
                context.Succeed(requirement);
            }

            return Task.CompletedTask;
        }
    }

    public class OwnerRequirement : IAuthorizationRequirement { }

    public class Query
    {
        [Authorize]
        [UseProjection]
        [UseFiltering]
        public async Task<User?> GetCurrentUser(
            [Service] IUserRepository repo,
            [Service] IAuthorizationService authService,
            ClaimsPrincipal claimsPrincipal)
        {
            var userIdClaim = claimsPrincipal.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            if (!int.TryParse(userIdClaim, out var userId))
            {
                return null;
            }

            var user = await repo.GetUserByIdAsync(userId);

            // Verify ownership even for "current user" queries
            var authResult = await authService.AuthorizeAsync(
                claimsPrincipal, user, new OwnerRequirement());

            if (!authResult.Succeeded)
            {
                throw new GraphQLException("Access denied");
            }

            return user;
        }
    }

    public class SecureUserType : ObjectType<User>
    {
        protected override void Configure(IObjectTypeDescriptor<User> descriptor)
        {
            descriptor.Field(u => u.Id);

            // SECURE: Field-level authorization for email
            descriptor.Field(u => u.Email)
                .Authorize("ViewEmail");

            // SECURE: SSN requires elevated permission
            descriptor.Field(u => u.SocialSecurityNumber)
                .Authorize("ViewSensitiveData")
                .Use(next => async context =>
                {
                    // Additional ownership check at field level
                    var user = context.Parent<User>();
                    var currentUserId = GetCurrentUserId(context);

                    if (user.Id != currentUserId)
                    {
                        context.ReportError("Cannot view other users' SSN");
                        return;
                    }

                    await next(context);
                });

            // SECURE: Filter orders to only show owned orders
            descriptor.Field(u => u.Orders)
                .Authorize()
                .UseFiltering()
                .Use(next => async context =>
                {
                    var currentUserId = GetCurrentUserId(context);
                    var user = context.Parent<User>();

                    // Only return orders if viewing own profile
                    if (user.Id != currentUserId)
                    {
                        context.Result = new List<Order>();
                        return;
                    }

                    await next(context);
                });

            // SECURE: Completely remove sensitive relationship from schema
            descriptor.Ignore(u => u.Friends);
        }

        private static int GetCurrentUserId(IResolverContext context)
        {
            var claim = context.GetUser()?.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            return int.TryParse(claim, out var id) ? id : 0;
        }
    }

    public class User
    {
        public int Id { get; set; }
        public string Email { get; set; } = string.Empty;
        public string SocialSecurityNumber { get; set; } = string.Empty;
        public List<Order> Orders { get; set; } = new();
        public List<User> Friends { get; set; } = new();
    }

    public class Order
    {
        public int Id { get; set; }
        public int UserId { get; set; }
        public decimal Total { get; set; }
    }
}
```

**Key Security Controls**:
- **Field-level authorization**: Each sensitive field has its own `[Authorize]` policy with ownership validation
- **Middleware interception**: Custom middleware on fields performs ownership checks before data resolution
- **Schema hiding**: Dangerous relationship fields (`Friends`) are removed from the schema entirely with `Ignore()`
- **Defense in depth**: Multiple authorization layers - policy-based, field middleware, and custom handlers

Excellent questions! Mutations require explicit ownership verification, and you need query complexity limits to prevent DoS attacks. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```csharp
using HotChocolate;
using HotChocolate.AspNetCore;
using HotChocolate.AspNetCore.Authorization;
using HotChocolate.Execution;
using HotChocolate.Execution.Configuration;
using HotChocolate.Resolvers;
using HotChocolate.Types;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Builder;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using System;
using System.Collections.Generic;
using System.Security.Claims;
using System.Threading.Tasks;

namespace ProductionGraphQL
{
    // Startup configuration
    public static class GraphQLSecurityConfiguration
    {
        public static IServiceCollection AddSecureGraphQL(this IServiceCollection services)
        {
            services
                .AddGraphQLServer()
                .AddQueryType<SecureQuery>()
                .AddMutationType<SecureMutation>()
                .AddType<SecureUserType>()
                .AddType<SecureOrderType>()
                .AddAuthorization()
                // SECURITY: Limit query depth to prevent nested traversal attacks
                .AddMaxExecutionDepthRule(5)
                // SECURITY: Limit query complexity to prevent DoS
                .SetRequestOptions(_ => new RequestExecutorOptions
                {
                    ExecutionTimeout = TimeSpan.FromSeconds(30)
                })
                .AddHttpRequestInterceptor<SecurityRequestInterceptor>()
                .UseDefaultPipeline()
                // SECURITY: Disable introspection in production
                .AddIntrospectionAllowedRule();

            // Authorization policies
            services.AddAuthorizationCore(options =>
            {
                options.AddPolicy("IsOwner", policy =>
                    policy.Requirements.Add(new ResourceOwnerRequirement()));
                options.AddPolicy("CanModifyUser", policy =>
                    policy.RequireRole("Admin", "UserManager")
                    .AddRequirements(new ResourceOwnerRequirement()));
                options.AddPolicy("ViewSensitiveData", policy =>
                    policy.RequireRole("Admin", "Compliance"));
            });

            services.AddSingleton<IAuthorizationHandler, ResourceOwnerAuthorizationHandler>();
            services.AddScoped<IAuditLogger, AuditLogger>();

            return services;
        }
    }

    // Request interceptor for logging and rate limiting context
    public class SecurityRequestInterceptor : DefaultHttpRequestInterceptor
    {
        private readonly ILogger<SecurityRequestInterceptor> _logger;

        public SecurityRequestInterceptor(ILogger<SecurityRequestInterceptor> logger)
        {
            _logger = logger;
        }

        public override ValueTask OnCreateAsync(
            HttpContext context,
            IRequestExecutor requestExecutor,
            IQueryRequestBuilder requestBuilder,
            CancellationToken cancellationToken)
        {
            // Log all GraphQL operations for audit trail
            var operationName = requestBuilder.GetQueryRequest()?.OperationName ?? "anonymous";
            var userId = context.User?.FindFirst(ClaimTypes.NameIdentifier)?.Value ?? "unauthenticated";
            var clientIp = context.Connection.RemoteIpAddress?.ToString() ?? "unknown";

            _logger.LogInformation(
                "GraphQL Request: Operation={Operation}, User={UserId}, IP={ClientIP}",
                operationName, userId, clientIp);

            // Add user context to GraphQL state
            requestBuilder.SetGlobalState("CurrentUserId", userId);
            requestBuilder.SetGlobalState("ClientIP", clientIp);
            requestBuilder.SetGlobalState("RequestTime", DateTime.UtcNow);

            return base.OnCreateAsync(context, requestExecutor, requestBuilder, cancellationToken);
        }
    }

    // Resource ownership authorization
    public class ResourceOwnerRequirement : IAuthorizationRequirement { }

    public class ResourceOwnerAuthorizationHandler : AuthorizationHandler<ResourceOwnerRequirement, IOwnable>
    {
        protected override Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            ResourceOwnerRequirement requirement,
            IOwnable resource)
        {
            var userIdClaim = context.User.FindFirst(ClaimTypes.NameIdentifier)?.Value;

            if (!int.TryParse(userIdClaim, out var userId))
            {
                return Task.CompletedTask;
            }

            // Admin role bypasses ownership check
            if (context.User.IsInRole("Admin"))
            {
                context.Succeed(requirement);
                return Task.CompletedTask;
            }

            if (resource.OwnerId == userId)
            {
                context.Succeed(requirement);
            }

            return Task.CompletedTask;
        }
    }

    // Secure mutation with ownership verification
    public class SecureMutation
    {
        public async Task<UserMutationResult> UpdateUser(
            UpdateUserInput input,
            [Service] IUserRepository repository,
            [Service] IAuthorizationService authService,
            [Service] IAuditLogger auditLogger,
            ClaimsPrincipal user,
            [GlobalState] string clientIp)
        {
            // Fetch the resource first
            var existingUser = await repository.GetUserByIdAsync(input.UserId);
            if (existingUser == null)
            {
                return new UserMutationResult
                {
                    Success = false,
                    Error = "User not found"
                };
            }

            // CRITICAL: Verify ownership before any modification
            var authResult = await authService.AuthorizeAsync(
                user, existingUser, "IsOwner");

            if (!authResult.Succeeded)
            {
                // Log unauthorized access attempt
                await auditLogger.LogSecurityEventAsync(new SecurityAuditEvent
                {
                    EventType = "UNAUTHORIZED_MUTATION_ATTEMPT",
                    TargetUserId = input.UserId,
                    AttemptingUserId = GetUserId(user),
                    ClientIP = clientIp,
                    Timestamp = DateTime.UtcNow,
                    Details = "Attempted to modify another user's profile"
                });

                return new UserMutationResult
                {
                    Success = false,
                    Error = "Access denied"
                };
            }

            // Input validation
            var validationErrors = ValidateInput(input);
            if (validationErrors.Any())
            {
                return new UserMutationResult
                {
                    Success = false,
                    Error = string.Join(", ", validationErrors)
                };
            }

            // Perform update with audit trail
            var previousState = existingUser.Clone();
            existingUser.Email = input.Email ?? existingUser.Email;
            existingUser.DisplayName = input.DisplayName ?? existingUser.DisplayName;

            await repository.UpdateUserAsync(existingUser);

            // Audit successful modification
            await auditLogger.LogDataModificationAsync(new DataModificationEvent
            {
                EntityType = "User",
                EntityId = existingUser.Id,
                ModifiedBy = GetUserId(user),
                PreviousState = previousState,
                NewState = existingUser,
                Timestamp = DateTime.UtcNow
            });

            return new UserMutationResult
            {
                Success = true,
                User = existingUser
            };
        }

        public async Task<OrderMutationResult> DeleteOrder(
            int orderId,
            [Service] IOrderRepository repository,
            [Service] IAuthorizationService authService,
            [Service] IAuditLogger auditLogger,
            ClaimsPrincipal user)
        {
            var order = await repository.GetOrderByIdAsync(orderId);
            if (order == null)
            {
                return new OrderMutationResult { Success = false, Error = "Order not found" };
            }

            // CRITICAL: Verify order ownership
            var authResult = await authService.AuthorizeAsync(user, order, "IsOwner");
            if (!authResult.Succeeded)
            {
                await auditLogger.LogSecurityEventAsync(new SecurityAuditEvent
                {
                    EventType = "UNAUTHORIZED_DELETE_ATTEMPT",
                    TargetUserId = order.OwnerId,
                    AttemptingUserId = GetUserId(user),
                    Details = $"Attempted to delete order {orderId}"
                });

                return new OrderMutationResult { Success = false, Error = "Access denied" };
            }

            // Soft delete with audit trail
            await repository.SoftDeleteOrderAsync(orderId, GetUserId(user));

            return new OrderMutationResult { Success = true };
        }

        private static int GetUserId(ClaimsPrincipal user)
        {
            var claim = user.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            return int.TryParse(claim, out var id) ? id : 0;
        }

        private static List<string> ValidateInput(UpdateUserInput input)
        {
            var errors = new List<string>();

            if (input.Email != null && !IsValidEmail(input.Email))
                errors.Add("Invalid email format");

            if (input.DisplayName != null && input.DisplayName.Length > 100)
                errors.Add("Display name too long");

            return errors;
        }

        private static bool IsValidEmail(string email) =>
            System.Text.RegularExpressions.Regex.IsMatch(
                email, @"^[^@\s]+@[^@\s]+\.[^@\s]+$");
    }

    // Secure query with filtered data access
    public class SecureQuery
    {
        [Authorize]
        public async Task<User?> GetMe(
            [Service] IUserRepository repo,
            ClaimsPrincipal user)
        {
            var userId = GetUserId(user);
            return await repo.GetUserByIdAsync(userId);
        }

        // Admin-only query for user lookup
        [Authorize(Roles = new[] { "Admin", "Support" })]
        public async Task<User?> GetUser(
            int id,
            [Service] IUserRepository repo,
            [Service] IAuditLogger auditLogger,
            ClaimsPrincipal user)
        {
            await auditLogger.LogDataAccessAsync(new DataAccessEvent
            {
                AccessedEntityType = "User",
                AccessedEntityId = id,
                AccessedBy = GetUserId(user),
                AccessReason = "Admin lookup"
            });

            return await repo.GetUserByIdAsync(id);
        }

        private static int GetUserId(ClaimsPrincipal user)
        {
            var claim = user.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            return int.TryParse(claim, out var id) ? id : 0;
        }
    }

    // Type definitions with field-level security
    public class SecureUserType : ObjectType<User>
    {
        protected override void Configure(IObjectTypeDescriptor<User> descriptor)
        {
            descriptor.Field(u => u.Id);
            descriptor.Field(u => u.DisplayName);

            // Email only visible to owner or admin
            descriptor.Field(u => u.Email)
                .Use(next => async context =>
                {
                    var user = context.Parent<User>();
                    var currentUserId = context.GetGlobalStateOrDefault<string>("CurrentUserId");
                    var claimsPrincipal = context.GetUser();

                    if (int.TryParse(currentUserId, out var id) && 
                        (user.Id == id || claimsPrincipal?.IsInRole("Admin") == true))
                    {
                        await next(context);
                    }
                    else
                    {
                        context.Result = "[REDACTED]";
                    }
                });

            // Completely hide SSN from GraphQL schema
            descriptor.Ignore(u => u.SocialSecurityNumber);

            // Orders filtered to owner only
            descriptor.Field(u => u.Orders)
                .Authorize()
                .Resolve(context =>
                {
                    var user = context.Parent<User>();
                    var currentUserId = context.GetGlobalStateOrDefault<string>("CurrentUserId");

                    if (!int.TryParse(currentUserId, out var id) || user.Id != id)
                    {
                        return Array.Empty<Order>();
                    }

                    return user.Orders;
                });
        }
    }

    public class SecureOrderType : ObjectType<Order>
    {
        protected override void Configure(IObjectTypeDescriptor<Order> descriptor)
        {
            descriptor.Field(o => o.Id);
            descriptor.Field(o => o.Total);
            descriptor.Field(o => o.CreatedAt);

            // Remove back-reference to prevent traversal attacks
            descriptor.Ignore(o => o.Owner);
        }
    }

    // Interfaces and models
    public interface IOwnable
    {
        int OwnerId { get; }
    }

    public class User : IOwnable
    {
        public int Id { get; set; }
        public string Email { get; set; } = string.Empty;
        public string DisplayName { get; set; } = string.Empty;
        public string SocialSecurityNumber { get; set; } = string.Empty;
        public List<Order> Orders { get; set; } = new();
        public int OwnerId => Id;

        public User Clone() => (User)MemberwiseClone();
    }

    public class Order : IOwnable
    {
        public int Id { get; set; }
        public int UserId { get; set; }
        public decimal Total { get; set; }
        public DateTime CreatedAt { get; set; }
        public User? Owner { get; set; }
        public int OwnerId => UserId;
    }

    public record UpdateUserInput(int UserId, string? Email, string? DisplayName);
    public record UserMutationResult(bool Success = false, string? Error = null, User? User = null);
    public record OrderMutationResult(bool Success = false, string? Error = null);
}
