// Program.cs - Disable introspection based on environment
var builder = WebApplication.CreateBuilder(args);

builder.Services
    .AddGraphQLServer()
    // Other configuration...
    .ModifyRequestOptions(opt =>
    {
        // Disable introspection in production
        if (builder.Environment.IsProduction())
        {
            opt.IncludeExceptionDetails = false;
        }
    })
    .AddIntrospectionAllowedRule()
    .ConfigureSchema(sb =>
    {
        if (builder.Environment.IsProduction())
        {
            // Require special header for introspection in prod
            sb.AddIntrospectionAllowedRule(context =>
            {
                var httpContext = context.ContextData
                    .GetValueOrDefault("HttpContext") as HttpContext;
                var authHeader = httpContext?.Request.Headers["X-Introspection-Auth"].FirstOrDefault();
                return authHeader == Environment.GetEnvironmentVariable("INTROSPECTION_SECRET");
            });
        }
    });
