# Authorization decorator for resolvers
def require_auth(fn):
    @wraps(fn)
    def wrapper(self, info, *args, **kwargs):
        user = get_current_user(info)
        if not user:
            raise Exception("Authentication required")
        return fn(self, info, *args, **kwargs)
    return wrapper

def get_current_user(info):
    """Extract authenticated user from request context"""
    return info.context.get('current_user')

def can_access_user(current_user, target_user_id):
    """Check if current user can access target user's data"""
    if not current_user:
        return False
    # Users can access their own data, admins can access anyone
    return current_user['id'] == target_user_id or current_user['role'] == 'admin'

def can_access_order(current_user, order):
    """Check if current user can access this order"""
    if not current_user:
        return False
    return order['user_id'] == current_user['id'] or current_user['role'] == 'admin'

class UserType(ObjectType):
    id = Int()
    name = String()
    email = String()
    role = String()
    orders = List(lambda: OrderType)

    def resolve_email(self, info):
        """Only return email if authorized"""
        current_user = get_current_user(info)
        if can_access_user(current_user, self.id):
            return self.email
        return None  # Hide email from unauthorized users

    def resolve_role(self, info):
        """Only admins can see role information"""
        current_user = get_current_user(info)
        if current_user and current_user['role'] == 'admin':
            return self.role
        return None

    def resolve_orders(self, info):
