        current_user = get_current_user(info)
        if not can_access_user(current_user, self.id):
            logger.warning(f"Unauthorized order access attempt: user {current_user['id'] if current_user else 'anonymous'} tried to access user {self.id}'s orders")
            return []  # Return empty list, don't reveal existence
        return [OrderType(**o) for o in orders_db.values() if o["user_id"] == self.id]

class OrderType(ObjectType):
    id = Int()
    user_id = Int()
    total = graphene.Float()
    items = List(String)
    user = Field(lambda: UserType)

    def resolve_user(self, info):
        """Authorization check on relationship traversal"""
        current_user = get_current_user(info)
        if not can_access_user(current_user, self.user_id):
            return None
        return UserType(**users_db[self.user_id])

class Query(ObjectType):
    user = Field(UserType, id=Int(required=True))
    me = Field(UserType)  # Safe alternative to allUsers

    @require_auth
    def resolve_user(self, info, id):
        current_user = get_current_user(info)
        # Authorization check at query level
        if not can_access_user(current_user, id):
            logger.warning(f"Unauthorized user access: {current_user['id']} attempted to access user {id}")
            raise Exception("Not authorized to access this user")
        if id in users_db:
            return UserType(**users_db[id])
        return None

    @require_auth
    def resolve_me(self, info):
        """Users can only query their own data"""
        current_user = get_current_user(info)
        return UserType(**current_user)

