};

// Context factory with authentication
const context = async ({ req }) => {
  const token = req.headers.authorization?.replace('Bearer ', '');
  let user = null;

  if (token) {
    try {
      user = jwt.verify(token, process.env.JWT_SECRET);
    } catch (err) {
      // Invalid token - user remains null
    }
  }

  return { user, req };
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context,
  plugins: [permissions],
  introspection: process.env.NODE_ENV !== 'production',
  playground: process.env.NODE_ENV !== 'production'
});
```

**Key Security Controls**:
- **Schema redesign**: Removed password field entirely, exposed only "me" and "my*" queries that scope to authenticated user
- **graphql-shield middleware**: Declarative authorization rules applied before resolvers execute
- **Data masking**: Payment card numbers return only last four digits
- **Introspection disabled**: Production environments don't expose schema to attackers
- **Audit logging**: Failed authorization attempts logged with user context

Multi-tenant GraphQL APIs with RBAC require careful architecture to prevent horizontal privilege escalation (accessing other orgs' data) and vertical privilege escalation (acting as admin). This pattern was exploited in multiple SaaS breaches including the 2024 Postman workspace exposure.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { ApolloServer, gql, AuthenticationError, ForbiddenError } = require('apollo-server-express');
const { shield, rule, and, or, chain } = require('graphql-shield');
const { createRateLimitRule } = require('graphql-rate-limit');
const winston = require('winston');
const { v4: uuidv4 } = require('uuid');

// Structured security logger
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  defaultMeta: { service: 'graphql-api' },
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Permission constants
const PERMISSIONS = {
  READ_USERS: 'read:users',
  WRITE_USERS: 'write:users',
  READ_ORDERS: 'read:orders',
  WRITE_ORDERS: 'write:orders',
  ADMIN: 'admin:all',
  ORG_ADMIN: 'admin:org'
};

const ROLES = {
  USER: [PERMISSIONS.READ_USERS, PERMISSIONS.READ_ORDERS],
  MANAGER: [PERMISSIONS.READ_USERS, PERMISSIONS.READ_ORDERS, PERMISSIONS.WRITE_ORDERS],
  ORG_ADMIN: [PERMISSIONS.READ_USERS, PERMISSIONS.WRITE_USERS, PERMISSIONS.READ_ORDERS, PERMISSIONS.WRITE_ORDERS, PERMISSIONS.ORG_ADMIN],
  SUPER_ADMIN: [PERMISSIONS.ADMIN]
};

// Rate limiting rule
const rateLimitRule = createRateLimitRule({
  identifyContext: (ctx) => ctx.user?.id || ctx.req.ip,
  formatError: () => new ForbiddenError('Rate limit exceeded')
});

// Authorization helper class
class AuthorizationService {
  constructor(user, dataSources, logger) {
    this.user = user;
    this.dataSources = dataSources;
    this.logger = logger;
    this.requestId = uuidv4();
  }

  hasPermission(permission) {
    if (!this.user) return false;
    const userPermissions = ROLES[this.user.role] || [];
    return userPermissions.includes(permission) || userPermissions.includes(PERMISSIONS.ADMIN);
  }

  async canAccessOrganization(orgId) {
    if (!this.user) return false;

    // Super admins can access all orgs
    if (this.hasPermission(PERMISSIONS.ADMIN)) return true;

    // Check if user belongs to the organization
    const membership = await this.dataSources.orgAPI.getUserMembership(
      this.user.id,
      orgId
    );

    return membership !== null;
  }

  async canAccessResource(resourceType, resourceId) {
    if (!this.user) return false;

    const resource = await this.dataSources[`${resourceType}API`].getById(resourceId);
    if (!resource) return false;

    // Check organization membership
    const canAccessOrg = await this.canAccessOrganization(resource.organizationId);

    if (!canAccessOrg) {
      this.logUnauthorizedAccess(resourceType, resourceId, 'org_mismatch');
      return false;
    }

    return true;
  }

  logUnauthorizedAccess(resourceType, resourceId, reason) {
    this.logger.warn({
      event: 'unauthorized_access_attempt',
      requestId: this.requestId,
      userId: this.user?.id,
      userRole: this.user?.role,
      userOrg: this.user?.organizationId,
      resourceType,
      resourceId,
      reason,
      timestamp: new Date().toISOString()
    });
  }

  logAccess(action, resourceType, resourceId) {
    this.logger.info({
      event: 'resource_access',
      requestId: this.requestId,
      userId: this.user.id,
      action,
      resourceType,
      resourceId,
      timestamp: new Date().toISOString()
    });
  }
}

// GraphQL Shield rules
const isAuthenticated = rule({ cache: 'contextual' })(
  async (parent, args, ctx) => {
    if (!ctx.user) {
      return new AuthenticationError('Authentication required');
    }
    return true;
  }
);

const hasPermission = (permission) => rule({ cache: 'contextual' })(
  async (parent, args, ctx) => {
    if (!ctx.authService.hasPermission(permission)) {
      ctx.authService.logUnauthorizedAccess('permission', permission, 'insufficient_permissions');
      return new ForbiddenError(`Missing permission: ${permission}`);
    }
    return true;
  }
);

const canAccessOrg = rule({ cache: 'strict' })(
  async (parent, { organizationId }, ctx) => {
    const canAccess = await ctx.authService.canAccessOrganization(organizationId);
    if (!canAccess) {
      return new ForbiddenError('Not authorized to access this organization');
    }
    return true;
  }
);

const canAccessUser = rule({ cache: 'strict' })(
  async (parent, { id }, ctx) => {
    // Users can always access their own data
    if (id === ctx.user.id) return true;

    // Check if target user is in same org
    const targetUser = await ctx.dataSources.userAPI.getUserById(id);
    if (!targetUser) {
      return new ForbiddenError('User not found');
    }

    const canAccess = await ctx.authService.canAccessOrganization(targetUser.organizationId);
    if (!canAccess) {
      ctx.authService.logUnauthorizedAccess('user', id, 'cross_org_access');
      return new ForbiddenError('Not authorized to access this user');
    }
    return true;
  }
);

// Query complexity limiting
const queryComplexityPlugin = {
  requestDidStart: () => ({
    didResolveOperation({ request, document }) {
      const complexity = calculateComplexity(document);
      if (complexity > 100) {
        throw new ForbiddenError('Query too complex');
      }
    }
  })
};

// Permission shield configuration
const permissions = shield({
  Query: {
    me: isAuthenticated,
    user: and(isAuthenticated, hasPermission(PERMISSIONS.READ_USERS), canAccessUser),
    organizationUsers: and(isAuthenticated, hasPermission(PERMISSIONS.READ_USERS), canAccessOrg),
    order: chain(isAuthenticated, rateLimitRule({ window: '1m', max: 100 }))
  },
  Mutation: {
    updateUser: and(isAuthenticated, hasPermission(PERMISSIONS.WRITE_USERS), canAccessUser),
    createOrder: and(isAuthenticated, hasPermission(PERMISSIONS.WRITE_ORDERS)),
    deleteOrganization: and(isAuthenticated, hasPermission(PERMISSIONS.ORG_ADMIN), canAccessOrg)
  },
  User: {
    // Field-level authorization
    email: isAuthenticated,
    salary: and(isAuthenticated, hasPermission(PERMISSIONS.ORG_ADMIN))
  }
}, {
  fallbackError: new ForbiddenError('Access denied'),
  allowExternalErrors: true,
  debug: process.env.NODE_ENV !== 'production'
});

// Secure resolvers with defense in depth
const resolvers = {
  Query: {
    me: async (_, __, { user, dataSources, authService }) => {
      authService.logAccess('read', 'user', user.id);
      return dataSources.userAPI.getUserById(user.id);
    },

    user: async (_, { id }, { dataSources, authService }) => {
      // Pre-authorized by shield, but verify again (defense in depth)
      const targetUser = await dataSources.userAPI.getUserById(id);
      if (!targetUser) return null;

      authService.logAccess('read', 'user', id);
      return targetUser;
    },

    organizationUsers: async (_, { organizationId }, { dataSources, authService }) => {
      authService.logAccess('read', 'organization_users', organizationId);
      return dataSources.userAPI.getUsersByOrganization(organizationId);
    }
  },

  Mutation: {
    updateUser: async (_, { id, input }, { dataSources, authService }) => {
      // Sanitize input - remove fields user shouldn't modify
      const sanitizedInput = {
        name: input.name,
        email: input.email
        // Explicitly exclude: role, organizationId, permissions
      };

      authService.logAccess('update', 'user', id);
      return dataSources.userAPI.updateUser(id, sanitizedInput);
    }
  },

  User: {
    // Resolver-level org check for nested queries (defense in depth)
    orders: async (user, _, { dataSources, authService }) => {
      const canAccess = await authService.canAccessOrganization(user.organizationId);
      if (!canAccess) {
        authService.logUnauthorizedAccess('user_orders', user.id, 'nested_query_bypass');
        return [];
      }
      return dataSources.orderAPI.getOrdersByUserId(user.id);
    }
  }
};

// Context factory with full security context
const context = async ({ req }) => {
  const token = req.headers.authorization?.replace('Bearer ', '');
  let user = null;

  if (token) {
    try {
      const decoded = jwt.verify(token, process.env.JWT_SECRET, {
        algorithms: ['RS256'],
        issuer: process.env.JWT_ISSUER,
        audience: process.env.JWT_AUDIENCE
      });

      // Fetch fresh user data (don't trust JWT claims for permissions)
      user = await dataSources.userAPI.getUserById(decoded.sub);
    } catch (err) {
      securityLogger.warn({
        event: 'invalid_token',
        error: err.message,
        ip: req.ip
      });
    }
  }

  const authService = new AuthorizationService(user, dataSources, securityLogger);

  return {
    user,
    req,
    authService,
    dataSources
  };
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context,
  plugins: [permissions, queryComplexityPlugin],
  introspection: false,
  playground: false,
  persistedQueries: {
    cache: new RedisCache({ host: process.env.REDIS_HOST })
  },
  formatError: (err) => {
    // Sanitize errors in production
    if (process.env.NODE_ENV === 'production') {
      if (err.extensions?.code === 'INTERNAL_SERVER_ERROR') {
        return new Error('Internal server error');
      }
    }
    return err;
  }
});

const app = express();

// Security headers
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('Content-Security-Policy', "default-src 'none'");
  next();
});

server.applyMiddleware({ app, path: '/graphql' });
```

**Defense in Depth Layers**:

1. **Authentication Layer**: JWT verification with algorithm pinning, issuer/audience validation, and fresh user data fetch
```javascript
jwt.verify(token, process.env.JWT_SECRET, {
  algorithms: ['RS256'],  // Prevent algorithm confusion attacks
  issuer: process.env.JWT_ISSUER,
  audience: process.env.JWT_AUDIENCE
});
```

2. **Schema-Level Authorization**: graphql-shield middleware applies before any resolver
```javascript
and(isAuthenticated, hasPermission(PERMISSIONS.READ_USERS), canAccessUser)
```

3. **Resolver-Level Verification**: Secondary checks in resolvers for defense in depth
```javascript
const canAccess = await authService.canAccessOrganization(user.organizationId);
if (!canAccess) return [];
```

4. **Query Complexity Analysis**: Prevents resource exhaustion via deeply nested queries
```javascript
if (complexity > 100) throw new ForbiddenError('Query too complex');
```

**Additional Protections**:
- **Persisted queries**: Only allow pre-approved queries in production, blocking arbitrary introspection
- **Field-level authorization**: Sensitive fields like `salary` require elevated permissions
- **Input sanitization**: Mutation resolvers explicitly whitelist allowed fields
- **Comprehensive audit logging**: Every access attempt logged with request ID for correlation
- **Rate limiting per user/IP**: Prevents enumeration attacks via query aliasing
- **Error sanitization**: Production errors don't leak implementation details

GraphQL authorization is tricky because queries can nest arbitrarily deep, and each resolver must independently verify permissions. A common mistake is only checking authorization at the top-level query, allowing attackers to traverse relationships and access unauthorized data.

**VULNERABLE CODE**:

```java
import graphql.kickstart.tools.GraphQLQueryResolver;
import graphql.kickstart.tools.GraphQLResolver;
import org.springframework.stereotype.Component;
import java.util.List;

@Component
public class UserQueryResolver implements GraphQLQueryResolver {

    private final UserRepository userRepository;
    private final SecurityContext securityContext;

    public UserQueryResolver(UserRepository userRepository, SecurityContext securityContext) {
        this.userRepository = userRepository;
        this.securityContext = securityContext;
    }

    // VULNERABLE: Only checks auth at top level
    public User getUser(Long id) {
        Long currentUserId = securityContext.getCurrentUserId();

        // Authorization check at query level only
        if (!id.equals(currentUserId)) {
            throw new UnauthorizedException("Cannot access other users");
        }

        return userRepository.findById(id).orElse(null);
    }
}

@Component
public class UserResolver implements GraphQLResolver<User> {

    private final OrderRepository orderRepository;
    private final PaymentRepository paymentRepository;

    public UserResolver(OrderRepository orderRepository, PaymentRepository paymentRepository) {
        this.orderRepository = orderRepository;
        this.paymentRepository = paymentRepository;
    }

    // VULNERABLE: No authorization check on nested resolver
    public List<Order> orders(User user) {
        return orderRepository.findByUserId(user.getId());
    }

    // VULNERABLE: No authorization check - exposes all payments
    public List<Payment> payments(User user) {
        return paymentRepository.findByUserId(user.getId());
    }
}

@Component
public class OrderResolver implements GraphQLResolver<Order> {

    private final UserRepository userRepository;

    public OrderResolver(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    // VULNERABLE: Allows traversing back to ANY user from order
    public User customer(Order order) {
        return userRepository.findById(order.getCustomerId()).orElse(null);
    }
}
```

**Attack Payload**:
```graphql
# Attacker queries their own user (passes top-level check)
# Then traverses through orders to access other users' data
query {
  getUser(id: 123) {  # Attacker's own ID - passes auth check
    orders {
      customer {  # No auth check - can resolve ANY customer
        id
        email
        ssn
        payments {  # Access other users' payment info
          cardNumber
          amount
        }
      }
    }
  }
}

# Alternative: Use introspection to find paths
query {
  __schema {
    types {
      name
      fields {
        name
        type { name }
      }
    }
  }
}
```

**Why This Is Dangerous**:
- Authorization only checked at the query entry point, not on nested resolvers
- Relationship traversal allows IDOR through related objects
- Attackers can navigate object graphs to reach unauthorized data
- GraphQL introspection reveals the entire schema for attack planning

**SECURE VERSION**:

```java
