@Service
public class AuthorizationService {

    private final SecurityContext securityContext;
    private final AuditLogger auditLogger;

    public AuthorizationService(SecurityContext securityContext,
                                 AuditLogger auditLogger) {
        this.securityContext = securityContext;
        this.auditLogger = auditLogger;
    }

    public void requireUserAccess(Long targetUserId) {
        Long currentUserId = securityContext.getCurrentUserId();
        boolean isAdmin = securityContext.hasRole("ADMIN");

        if (!targetUserId.equals(currentUserId) && !isAdmin) {
            auditLogger.logUnauthorizedAccess(currentUserId, targetUserId, "User");
            throw new AccessDeniedException(
                "Access denied to user resource");
        }
    }
}
```

**Key Security Controls**:
- Every resolver independently verifies authorization before returning data
- Centralized AuthorizationService ensures consistent policy enforcement
- Audit logging captures all unauthorized access attempts
- Role-based exceptions (admin) are explicitly handled and logged

Excellent question! GraphQL aliases and batching create additional attack surfaces. Aliases allow executing the same query multiple times in a single request, enabling enumeration attacks. Batch mutations can attempt to modify multiple resources, hoping one bypasses authorization.

**PRODUCTION PATTERN**:

```java
import graphql.kickstart.tools.GraphQLMutationResolver;
import graphql.execution.instrumentation.Instrumentation;
import graphql.execution.instrumentation.InstrumentationContext;
import graphql.execution.instrumentation.parameters.InstrumentationFieldFetchParameters;
import graphql.schema.DataFetcher;
import org.springframework.stereotype.Component;
import io.github.bucket4j.Bucket;
import io.github.bucket4j.Bandwidth;
import java.time.Duration;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

// Custom instrumentation for field-level authorization
@Component
public class AuthorizationInstrumentation implements Instrumentation {

    private final AuthorizationService authService;
    private final QueryComplexityAnalyzer complexityAnalyzer;
    private final AuditLogger auditLogger;

    // Rate limit buckets per user
    private final Map<Long, Bucket> userBuckets = new ConcurrentHashMap<>();

    public AuthorizationInstrumentation(AuthorizationService authService,
                                         QueryComplexityAnalyzer complexityAnalyzer,
                                         AuditLogger auditLogger) {
        this.authService = authService;
        this.complexityAnalyzer = complexityAnalyzer;
        this.auditLogger = auditLogger;
    }

    @Override
    public InstrumentationContext<Object> beginFieldFetch(
            InstrumentationFieldFetchParameters parameters) {

        String fieldName = parameters.getField().getName();
        String parentType = parameters.getExecutionStepInfo()
            .getParent().getType().getName();

        // Log field access for audit trail
        auditLogger.logFieldAccess(fieldName, parentType);

        return InstrumentationContext.noOp();
    }

    public void validateQueryBeforeExecution(String query, Long userId) {
        // Check rate limit per user
        Bucket bucket = userBuckets.computeIfAbsent(userId, 
            id -> createUserBucket());

        if (!bucket.tryConsume(1)) {
            auditLogger.logRateLimitExceeded(userId);
            throw new RateLimitExceededException(
                "Query rate limit exceeded. Try again later.");
        }

        // Analyze query complexity to prevent DoS
        int complexity = complexityAnalyzer.calculateComplexity(query);
        if (complexity > 100) {
            auditLogger.logComplexityExceeded(userId, complexity);
            throw new QueryComplexityExceededException(
                "Query too complex. Simplify and retry.");
        }

        // Count aliases to prevent enumeration
        int aliasCount = complexityAnalyzer.countAliases(query);
        if (aliasCount > 10) {
            auditLogger.logAliasAbuse(userId, aliasCount);
            throw new QueryValidationException(
                "Too many aliased queries. Maximum 10 allowed.");
        }
    }

    private Bucket createUserBucket() {
        Bandwidth limit = Bandwidth.simple(100, Duration.ofMinutes(1));
        return Bucket.builder().addLimit(limit).build();
    }
}

// Secure mutation resolver with batch protection
@Component
public class SecureUserMutationResolver implements GraphQLMutationResolver {

    private final UserRepository userRepository;
    private final AuthorizationService authService;
    private final InputValidator validator;
    private final AuditLogger auditLogger;
    private final TransactionTemplate transactionTemplate;

    public SecureUserMutationResolver(UserRepository userRepository,
                                       AuthorizationService authService,
                                       InputValidator validator,
                                       AuditLogger auditLogger,
                                       TransactionTemplate transactionTemplate) {
        this.userRepository = userRepository;
        this.authService = authService;
        this.validator = validator;
        this.auditLogger = auditLogger;
        this.transactionTemplate = transactionTemplate;
    }

    public User updateUser(Long id, UserInput input) {
        // 1. Validate input structure
        validator.validate(input);

        // 2. Authorize access to target resource
        authService.requireUserAccess(id);

        // 3. Perform mutation in transaction with audit
        return transactionTemplate.execute(status -> {
            User user = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User not found"));

            // 4. Log before and after states
            String beforeState = user.toAuditString();

            // 5. Apply validated changes
            if (input.getEmail() != null) {
                validator.validateEmail(input.getEmail());
                user.setEmail(input.getEmail());
            }
            if (input.getName() != null) {
                validator.validateName(input.getName());
                user.setName(input.getName());
            }

            User saved = userRepository.save(user);

            // 6. Audit log the mutation
            auditLogger.logMutation("updateUser", id, 
                beforeState, saved.toAuditString(),
                authService.getCurrentUserId());

            return saved;
        });
    }

    // Secure batch operation with per-item authorization
    public List<User> updateUsers(List<UserUpdateInput> inputs) {
        // Limit batch size
        if (inputs.size() > 25) {
            throw new QueryValidationException(
                "Batch size exceeds maximum of 25 items");
        }

        // Pre-validate ALL authorization before any mutations
        for (UserUpdateInput input : inputs) {
            authService.requireUserAccess(input.getId());
        }

        // Execute in single transaction for atomicity
        return transactionTemplate.execute(status -> {
            List<User> results = new ArrayList<>();
            for (UserUpdateInput input : inputs) {
                User updated = updateUserInternal(input);
                results.add(updated);
            }
            return results;
        });
    }
}

// Query complexity analyzer
@Component
public class QueryComplexityAnalyzer {

    private static final Map<String, Integer> FIELD_COSTS = Map.of(
        "users", 10,
        "orders", 5,
        "payments", 8,
        "customer", 3
    );

    public int calculateComplexity(String query) {
        int complexity = 0;
        int depth = 0;

        for (char c : query.toCharArray()) {
            if (c == '{') depth++;
            if (c == '}') depth--;
        }

        for (Map.Entry<String, Integer> entry : FIELD_COSTS.entrySet()) {
            if (query.contains(entry.getKey())) {
                complexity += entry.getValue() * depth;
            }
        }

        return complexity;
    }

    public int countAliases(String query) {
        // Count patterns like "alias: fieldName"
        java.util.regex.Pattern aliasPattern = 
            java.util.regex.Pattern.compile("\\w+\\s*:\\s*\\w+\\s*[({]");
        java.util.regex.Matcher matcher = aliasPattern.matcher(query);

        int count = 0;
        while (matcher.find()) {
            count++;
        }
        return count;
    }
}

// GraphQL configuration with security features
@Configuration
public class GraphQLSecurityConfig {

    @Bean
    public GraphQLServlet graphQLServlet(
            GraphQLSchema schema,
            AuthorizationInstrumentation authInstrumentation) {

        return GraphQLServlet.builder()
            .schema(schema)
            .instrumentation(authInstrumentation)
            // Disable introspection in production
            .introspectionEnabled(
                !"production".equals(System.getenv("ENVIRONMENT")))
            .build();
    }

    @Bean
    public GraphQLSchema schema(GraphQLSchemaGenerator generator) {
        return generator
            // Apply directives for field-level security
            .withDirective("auth", new AuthDirective())
            .generate();
    }
}

// Custom directive for declarative authorization
public class AuthDirective implements SchemaDirectiveWiring {

    @Override
    public GraphQLFieldDefinition onField(
            SchemaDirectiveWiringEnvironment<GraphQLFieldDefinition> env) {

        GraphQLFieldDefinition field = env.getElement();
        DataFetcher<?> originalFetcher = env.getCodeRegistry()
            .getDataFetcher(env.getFieldsContainer(), field);

        // Wrap with authorization check
        DataFetcher<?> securedFetcher = dataFetchingEnv -> {
            // Get required role from directive argument
            String requiredRole = env.getDirective().getArgument("role")
                .getValue().toString();

            AuthorizationService authService = dataFetchingEnv
                .getGraphQlContext().get("authService");

            if (!authService.hasRole(requiredRole)) {
                throw new AccessDeniedException(
                    "Role '" + requiredRole + "' required for field: " + 
                    field.getName());
            }

            return originalFetcher.get(dataFetchingEnv);
        };

        env.getCodeRegistry().dataFetcher(
            env.getFieldsContainer(), field, securedFetcher);

        return field;
    }
}
```

**Defense in Depth Layers**:

1. **Query Complexity Analysis** - Prevent DoS through expensive nested queries:
```java
if (complexityAnalyzer.calculateComplexity(query) > MAX_COMPLEXITY) {
    throw new QueryComplexityExceededException("Query too complex");
}
```

2. **Alias/Batch Limiting** - Prevent enumeration attacks:
```java
if (complexityAnalyzer.countAliases(query) > MAX_ALIASES) {
    throw new QueryValidationException("Too many aliases");
}
```

3. **Per-Field Authorization** - Check at every resolver level:
```java
@Override
public User customer(Order order) {
    authService.requireUserAccess(order.getCustomerId());
    return userRepository.findById(order.getCustomerId()).orElse(null);
}
```

**Additional Protections**:
- Disable introspection in production to hide schema from attackers
- Use custom directives (@auth) for declarative field-level security
- Rate limit by user with sliding window (100 requests/minute)
- Comprehensive audit logging of all field accesses and mutations
- Transactional batch operations with pre-validation of all authorizations
- Query depth limiting to prevent deeply nested traversal attacks

GraphQL authorization is tricky because the flexible query structure allows attackers to access data through nested relationships that bypass top-level authorization checks. This is exactly what happened in CVE-2024-4835 where GitLab's GraphQL API allowed unauthorized access to private resources.

**VULNERABLE CODE**:

```go
package graph

import (
	"context"
	"database/sql"
	"errors"

	"github.com/99designs/gqlgen/graphql"
	"myapp/graph/model"
)

type Resolver struct {
	DB *sql.DB
}

// Query resolver - checks auth at top level only
func (r *queryResolver) User(ctx context.Context, id string) (*model.User, error) {
	// Get current user from context
	currentUser := ctx.Value("user").(*model.User)

	// Only check if user is authenticated, not authorized
	if currentUser == nil {
		return nil, errors.New("not authenticated")
	}

	// VULNERABLE: No check if currentUser can access requested user's data
	var user model.User
	err := r.DB.QueryRow(
		"SELECT id, name, email FROM users WHERE id = $1",
		id,
	).Scan(&user.ID, &user.Name, &user.Email)

	return &user, err
}

// VULNERABLE: Nested resolver with no authorization
func (r *userResolver) PrivateDocuments(ctx context.Context, obj *model.User) ([]*model.Document, error) {
	// No authorization check - assumes parent resolver validated access
	rows, err := r.DB.Query(
		"SELECT id, title, content, classification FROM documents WHERE owner_id = $1",
		obj.ID,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var docs []*model.Document
	for rows.Next() {
		var doc model.Document
		rows.Scan(&doc.ID, &doc.Title, &doc.Content, &doc.Classification)
		docs = append(docs, &doc)
	}
	return docs, nil
}
```

**Attack Payload**:
```graphql
# Attacker queries another user's private documents
query {
  user(id: "victim-user-id-123") {
    id
    name
    email
    privateDocuments {
      id
      title
      content
      classification
    }
  }
}
```

**Why This Is Dangerous**:
- Authorization only checks authentication, not whether the requesting user can access the target user's data
- Nested resolvers trust that parent resolvers performed authorization, creating an authorization gap
- Attackers can enumerate user IDs and access any user's private documents
- No field-level authorization on sensitive fields like `classification`

**SECURE VERSION**:

```go
package graph

import (
	"context"
	"database/sql"
	"errors"
	"log"

	"github.com/99designs/gqlgen/graphql"
	"myapp/graph/model"
)

var (
	ErrNotAuthenticated = errors.New("not authenticated")
	ErrNotAuthorized    = errors.New("not authorized to access this resource")
)

type Resolver struct {
	DB     *sql.DB
	Logger *log.Logger
}

// Authorization helper - checks resource access
func (r *Resolver) canAccessUser(ctx context.Context, targetUserID string) error {
	currentUser, ok := ctx.Value("user").(*model.User)
	if !ok || currentUser == nil {
		return ErrNotAuthenticated
	}

	// Users can only access their own data, unless admin
	if currentUser.ID != targetUserID && !currentUser.IsAdmin {
		r.Logger.Printf("AUTHZ_DENIED: user=%s attempted access to user=%s", 
			currentUser.ID, targetUserID)
		return ErrNotAuthorized
	}

	return nil
}

// Query resolver with proper authorization
func (r *queryResolver) User(ctx context.Context, id string) (*model.User, error) {
	// Check authorization BEFORE fetching data
	if err := r.canAccessUser(ctx, id); err != nil {
		return nil, err
	}

	var user model.User
	err := r.DB.QueryRow(
		"SELECT id, name, email FROM users WHERE id = $1",
		id,
	).Scan(&user.ID, &user.Name, &user.Email)

	if err == sql.ErrNoRows {
		return nil, errors.New("user not found")
	}
	return &user, err
}

// SECURE: Nested resolver with independent authorization check
func (r *userResolver) PrivateDocuments(ctx context.Context, obj *model.User) ([]*model.Document, error) {
	// CRITICAL: Re-check authorization at every resolver level
	if err := r.canAccessUser(ctx, obj.ID); err != nil {
		return nil, err
	}

	rows, err := r.DB.Query(
		"SELECT id, title, content, classification FROM documents WHERE owner_id = $1",
		obj.ID,
	)
	if err != nil {
		return nil, errors.New("failed to fetch documents")
	}
	defer rows.Close()

	var docs []*model.Document
	for rows.Next() {
		var doc model.Document
		if err := rows.Scan(&doc.ID, &doc.Title, &doc.Content, &doc.Classification); err != nil {
			continue
		}
		docs = append(docs, &doc)
	}
	return docs, nil
}
```

**Key Security Controls**:
- **Independent authorization at each resolver**: Every resolver performs its own authorization check, never trusting parent resolvers
- **Centralized authorization logic**: `canAccessUser()` helper ensures consistent policy enforcement
- **Audit logging**: Failed authorization attempts are logged with user context for security monitoring
- **Error message sanitization**: Generic errors returned to prevent information disclosure

Excellent questions! Production GraphQL APIs need multiple layers of defense: role-based access control (RBAC), field-level permissions, query complexity limits, and introspection controls. Here's a comprehensive production pattern.

**PRODUCTION PATTERN**:

```go
package graph

import (
	"context"
	"database/sql"
	"errors"
	"fmt"
	"log"
	"time"

	"github.com/99designs/gqlgen/graphql"
	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/extension"
	"github.com/vektah/gqlparser/v2/ast"
	"myapp/graph/model"
)

// Role definitions
type Role string

const (
	RoleUser    Role = "user"
	RoleManager Role = "manager"
	RoleAdmin   Role = "admin"
)

// Permission defines field-level access
type Permission struct {
	AllowedRoles []Role
	Condition    func(ctx context.Context, obj interface{}) bool
}

// FieldPermissions maps type.field to permissions
var FieldPermissions = map[string]Permission{
	"User.email": {
		AllowedRoles: []Role{RoleUser, RoleManager, RoleAdmin},
		Condition: func(ctx context.Context, obj interface{}) bool {
			// Users can see their own email, managers/admins can see all
			user := obj.(*model.User)
			current := GetCurrentUser(ctx)
			return current.ID == user.ID || hasRole(current, RoleManager, RoleAdmin)
		},
	},
	"User.ssn": {
		AllowedRoles: []Role{RoleAdmin},
		Condition:    nil, // Admin only, no additional condition
	},
	"Document.classification": {
		AllowedRoles: []Role{RoleManager, RoleAdmin},
		Condition:    nil,
	},
	"AuditLog.ipAddress": {
		AllowedRoles: []Role{RoleAdmin},
		Condition:    nil,
	},
}

// AuthorizationMiddleware implements field-level RBAC
type AuthorizationMiddleware struct {
	Logger *log.Logger
}

func (a *AuthorizationMiddleware) ExtensionName() string {
	return "AuthorizationMiddleware"
}

func (a *AuthorizationMiddleware) Validate(schema graphql.ExecutableSchema) error {
	return nil
}

func (a *AuthorizationMiddleware) InterceptField(ctx context.Context, next graphql.Resolver) (interface{}, error) {
	fc := graphql.GetFieldContext(ctx)
	fieldKey := fmt.Sprintf("%s.%s", fc.Object, fc.Field.Name)

	// Check field-level permissions
	perm, exists := FieldPermissions[fieldKey]
	if exists {
		currentUser := GetCurrentUser(ctx)
		if currentUser == nil {
			a.Logger.Printf("AUTHZ_FIELD_DENIED: anonymous access to %s", fieldKey)
			return nil, nil // Return null for unauthorized fields
		}

		// Check role-based access
		if !hasRole(currentUser, perm.AllowedRoles...) {
			a.Logger.Printf("AUTHZ_FIELD_DENIED: user=%s role=%s field=%s",
				currentUser.ID, currentUser.Role, fieldKey)
			return nil, nil // Return null instead of error to prevent enumeration
		}
	}

	// Execute resolver
	result, err := next(ctx)

	// Post-resolution condition check (for object-level conditions)
	if exists && perm.Condition != nil && result != nil {
		if !perm.Condition(ctx, result) {
			return nil, nil
		}
	}

	return result, err
}

// ComplexityLimitMiddleware prevents query depth/complexity attacks
type ComplexityLimitMiddleware struct {
	MaxComplexity int
	MaxDepth      int
	Logger        *log.Logger
}

func (c *ComplexityLimitMiddleware) ExtensionName() string {
	return "ComplexityLimit"
}

func (c *ComplexityLimitMiddleware) Validate(schema graphql.ExecutableSchema) error {
	return nil
}

func (c *ComplexityLimitMiddleware) MutateOperationContext(ctx context.Context, rc *graphql.OperationContext) *graphql.ResponseError {
	// Check query depth
	depth := calculateDepth(rc.Operation.SelectionSet, 0)
	if depth > c.MaxDepth {
		c.Logger.Printf("QUERY_DEPTH_EXCEEDED: depth=%d max=%d", depth, c.MaxDepth)
		return &graphql.ResponseError{
			Message: fmt.Sprintf("query depth %d exceeds maximum %d", depth, c.MaxDepth),
		}
	}
	return nil
}

func calculateDepth(selectionSet ast.SelectionSet, currentDepth int) int {
	maxDepth := currentDepth
	for _, selection := range selectionSet {
		if field, ok := selection.(*ast.Field); ok {
			if field.SelectionSet != nil {
				d := calculateDepth(field.SelectionSet, currentDepth+1)
				if d > maxDepth {
					maxDepth = d
				}
			}
		}
	}
	return maxDepth
}

// Secure resolver with comprehensive authorization
func (r *queryResolver) Users(ctx context.Context, filter *model.UserFilter) ([]*model.User, error) {
	currentUser := GetCurrentUser(ctx)
	if currentUser == nil {
		return nil, ErrNotAuthenticated
	}

	// Role-based query scope
	var query string
	var args []interface{}

	switch currentUser.Role {
	case string(RoleAdmin):
		// Admins can see all users
		query = "SELECT id, name, email, role, department FROM users WHERE 1=1"
	case string(RoleManager):
		// Managers can only see users in their department
		query = "SELECT id, name, email, role, department FROM users WHERE department = $1"
		args = append(args, currentUser.Department)
	default:
		// Regular users can only see themselves
		query = "SELECT id, name, email, role, department FROM users WHERE id = $1"
		args = append(args, currentUser.ID)
	}

	// Audit log the query
	r.Logger.Printf("AUTHZ_QUERY: user=%s role=%s action=list_users scope=%s",
		currentUser.ID, currentUser.Role, getQueryScope(currentUser))

	rows, err := r.DB.QueryContext(ctx, query, args...)
	if err != nil {
		return nil, errors.New("failed to fetch users")
	}
	defer rows.Close()

	var users []*model.User
	for rows.Next() {
		var user model.User
		if err := rows.Scan(&user.ID, &user.Name, &user.Email, &user.Role, &user.Department); err != nil {
			continue
		}
		users = append(users, &user)
	}
	return users, nil
}

// Helper functions
func GetCurrentUser(ctx context.Context) *model.User {
	user, ok := ctx.Value("user").(*model.User)
	if !ok {
		return nil
	}
	return user
}

func hasRole(user *model.User, roles ...Role) bool {
	for _, role := range roles {
		if Role(user.Role) == role {
			return true
		}
	}
	return false
}

func getQueryScope(user *model.User) string {
	switch Role(user.Role) {
	case RoleAdmin:
		return "global"
	case RoleManager:
		return "department:" + user.Department
	default:
		return "self"
	}
}

// Server setup with all protections
func NewGraphQLHandler(db *sql.DB, logger *log.Logger) *handler.Server {
	srv := handler.NewDefaultServer(NewExecutableSchema(Config{
		Resolvers: &Resolver{DB: db, Logger: logger},
	}))

	// Add authorization middleware
	srv.Use(&AuthorizationMiddleware{Logger: logger})

	// Add complexity limits
	srv.Use(&ComplexityLimitMiddleware{
		MaxComplexity: 200,
		MaxDepth:      10,
		Logger:        logger,
	})

	// Disable introspection in production
	if !isDevEnvironment() {
		srv.Use(extension.Introspection{})
	}

	// Add automatic persisted queries for production
	srv.Use(extension.AutomaticPersistedQuery{
		Cache: NewLRUCache(1000),
	})

	return srv
}

func isDevEnvironment() bool {
	// Check environment variable
	return false // Default to production-safe
}
```

**Defense in Depth Layers**:

1. **Query Complexity Limiting**:
```go
// Prevent resource exhaustion via deeply nested queries
func (c *ComplexityLimitMiddleware) MutateOperationContext(ctx context.Context, rc *graphql.OperationContext) *graphql.ResponseError {
    depth := calculateDepth(rc.Operation.SelectionSet, 0)
    if depth > c.MaxDepth {
        return &graphql.ResponseError{Message: "query too complex"}
    }
    return nil
}
```

2. **Field-Level Authorization**:
```go
// Null out sensitive fields for unauthorized users
if !hasRole(currentUser, perm.AllowedRoles...) {
    return nil, nil // Return null, not error (prevents enumeration)
}
```

3. **Query Scope Restriction**:
```go
// Automatically scope queries based on user role
switch currentUser.Role {
case "admin":
    query = "SELECT * FROM users" // Full access
case "manager":
    query = "SELECT * FROM users WHERE department = $1" // Department only
default:
    query = "SELECT * FROM users WHERE id = $1" // Self only
}
```

**Additional Protections**:
- **Introspection disabled in production**: Prevents attackers from discovering schema structure
- **Persisted queries**: Only allow pre-approved queries in production, blocking arbitrary query construction
- **Rate limiting per user/IP**: Prevent brute-force enumeration attacks
- **Audit logging**: Every authorization decision is logged with user context, action, and scope for SIEM integration
- **Null response for denied fields**: Returns null instead of errors to prevent field enumeration attacks
- **Context deadline enforcement**: Prevents long-running queries from exhausting server resources
